// 伪代码：流式响应处理的核心逻辑
async function handleStreamResponse(): Promise<void> {
  let currentSection: 'thinking' | 'tool' | 'content' = 'thinking';
  let accumulatedContent = '';

  for await (const chunk of apiStream) {
    const token = chunk.token;

    if (isToolCallStart(token)) {
      currentSection = 'tool';
      await executeToolCall(parseToolCall(token));
    } else if (isToolCallEnd(token)) {
      currentSection = 'content';
    } else if (currentSection === 'thinking') {
      renderThinking(token);
    } else {
      accumulatedContent += token;
      renderContent(token);
    }
  }

  // 流式输出完成后的最终处理
  finalizeContent(accumulatedContent);
}
